import{_ as t,o as a,c as i,a7 as o}from"./chunks/framework.C4ZIv4ii.js";const h=JSON.parse('{"title":"Global Sections","description":"","frontmatter":{},"headers":[],"relativePath":"builder/global-sections.md","filePath":"builder/global-sections.md","lastUpdated":1781554731000}'),l={name:"builder/global-sections.md"};function n(r,e,s,c,d,g){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="global-sections" tabindex="-1">Global Sections <a class="header-anchor" href="#global-sections" aria-label="Permalink to &quot;Global Sections&quot;">​</a></h1><p>A Global Section is a container saved once and reused across multiple pages. When you edit the Global Section, every page that uses it updates automatically.</p><h2 id="creating-a-global-section" tabindex="-1">Creating a Global Section <a class="header-anchor" href="#creating-a-global-section" aria-label="Permalink to &quot;Creating a Global Section&quot;">​</a></h2><ol><li>Open any page in the Falcon Builder</li><li>Build your container (e.g., a newsletter signup banner)</li><li>Right-click the container toolbar</li><li>Select <strong>Save as Global Section</strong></li><li>Give it a name (e.g., &quot;Newsletter Banner&quot;)</li></ol><p>The section is saved and available site-wide.</p><h2 id="inserting-a-global-section" tabindex="-1">Inserting a Global Section <a class="header-anchor" href="#inserting-a-global-section" aria-label="Permalink to &quot;Inserting a Global Section&quot;">​</a></h2><ol><li>Open any page in the Falcon Builder</li><li>Click <strong>+ Add Container</strong> (or click between containers)</li><li>In the <strong>Column Select</strong> modal, click the <strong>Global Sections</strong> tab</li><li>Click <strong>Insert</strong> on the section you want</li></ol><p>The container appears on the page, linked to the Global Section.</p><h2 id="editing-a-global-section" tabindex="-1">Editing a Global Section <a class="header-anchor" href="#editing-a-global-section" aria-label="Permalink to &quot;Editing a Global Section&quot;">​</a></h2><p><strong>Option 1 — Edit in-place:</strong> Click the Global Section container in the builder and edit its elements normally. Changes save to the global section and propagate everywhere.</p><p><strong>Option 2 — From the Sections Manager:</strong></p><ol><li>Go to <strong>Admin → Appearance → Builder Sections</strong></li><li>Find your section and click <strong>Edit</strong></li><li>Opens the builder for that specific section</li></ol><h2 id="deleting-a-global-section" tabindex="-1">Deleting a Global Section <a class="header-anchor" href="#deleting-a-global-section" aria-label="Permalink to &quot;Deleting a Global Section&quot;">​</a></h2><ol><li>Go to <strong>Admin → Appearance → Builder Sections</strong></li><li>Click <strong>Delete</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Deleting a Global Section removes it from all pages that were using it.</p></div><h2 id="global-section-vs-library" tabindex="-1">Global Section vs Library <a class="header-anchor" href="#global-section-vs-library" aria-label="Permalink to &quot;Global Section vs Library&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Global Section</th><th>Library</th></tr></thead><tbody><tr><td>Synced across pages</td><td>✅ Yes — edit once, update everywhere</td><td>❌ No — each insert is independent</td></tr><tr><td>Use case</td><td>Repeated elements (header CTA, newsletter banner, sale strip)</td><td>Save a design to reuse as a starting point</td></tr><tr><td>Editable per-page</td><td>❌ No</td><td>✅ Yes</td></tr></tbody></table>',17)])])}const p=t(l,[["render",n]]);export{h as __pageData,p as default};
